insert into student_passes(id,school_id,student_id,token_hash,demo_token,token_type,status) select replace(id::text,'50000000','70000000')::uuid,school_id,id,encode(extensions.digest(case admission_no when 'SPS001' then 'stp_live_aarav_001' when 'SPS002' then 'stp_live_meera_002' when 'SPS003' then 'stp_live_riya_003' when 'SPS004' then 'stp_live_kabir_004' when 'SPS011' then 'stp_live_route7_005' when 'GVA001' then 'stp_gva_ira_001' else 'stp_demo_'||admission_no end,'sha256'),'hex'),case admission_no when 'SPS001' then 'stp_live_aarav_001' when 'SPS002' then 'stp_live_meera_002' when 'SPS003' then 'stp_live_riya_003' when 'SPS004' then 'stp_live_kabir_004' when 'SPS011' then 'stp_live_route7_005' when 'GVA001' then 'stp_gva_ira_001' else 'stp_demo_'||admission_no end,'qr','active' from students;
insert into student_route_assignments(id,school_id,student_id,route_id,stop_id,effective_from) select gen_random_uuid(),school_id,id,case when admission_no='SPS011' then '20000000-0000-4000-8000-000000000007'::uuid when admission_no='GVA001' then '20000000-0000-4000-8000-000000000107'::uuid else '20000000-0000-4000-8000-000000000004'::uuid end,case when admission_no='SPS011' then '80000000-0000-4000-8000-000000000011'::uuid when admission_no='GVA001' then '80000000-0000-4000-8000-000000000101'::uuid when admission_no in('SPS002','SPS005','SPS009') then '80000000-0000-4000-8000-000000000002'::uuid when admission_no in('SPS003','SPS006','SPS010') then '80000000-0000-4000-8000-000000000003'::uuid when admission_no='SPS007' then '80000000-0000-4000-8000-000000000004'::uuid else '80000000-0000-4000-8000-000000000001'::uuid end,current_date from students;
insert into boarding_events(school_id,student_id,student_pass_id,route_id,vehicle_id,driver_user_id,service_date,status,occurred_at,location_status,latitude,longitude,sync_source,idempotency_key,client_device_id) select school_id,id,replace(id::text,'50000000','70000000')::uuid,'20000000-0000-4000-8000-000000000004','30000000-0000-4000-8000-000000000012','40000000-0000-4000-8000-000000000001',current_date,'confirmed',date_trunc('day',now() at time zone 'Asia/Kolkata') at time zone 'Asia/Kolkata'+interval '7 hours 20 minutes'+((substring(admission_no,4)::int)-4)*interval '1 minute','simulated',26.9124,75.7873,'demo','seed-'||current_date||'-'||admission_no,'seed' from students where admission_no between 'SPS004' and 'SPS010';
